import type { WorkspaceConfiguration} from 'vscode';

import { isSupportedLanguageId } from '@github/copilot-promptlib';
import * as vscode from 'vscode';
import { CopilotConfigPrefix } from '../../lib/src/constants';
import { ABExperiments } from './abexperiments';
import { BlockMode, BlockModeConfig, ConfigKey, ConfigKeyType, ConfigProvider, getConfigDefaultForObjectKey, setConfigProvider, VscInfo } from '../../lib/src/config';
import { Context } from '../../lib/src/context';
import { inTestMode } from '../../lib/src/testing/testMode';

const packageJson = require('../../package.json');

let config: WorkspaceConfiguration;
if (!process.env.IS_AGENT) {
    config = vscode.workspace.getConfiguration(CopilotConfigPrefix);
}
let extension: vscode.Extension<any> | undefined;

if (!process.env.IS_AGENT) {
    // Reload cached config if a workspace config change effects Copilot namespace
    vscode.workspace.onDidChangeConfiguration((changeEvent) => {
        if (changeEvent.affectsConfiguration(CopilotConfigPrefix)) {
            config = vscode.workspace.getConfiguration(CopilotConfigPrefix);
        }
    });
}
function getConfigKeyFromObject<T>(key: string, objectKey: string): T {
    const value = config[key][objectKey];
    if (value === undefined) {
        return getConfigDefaultForObjectKey(key, objectKey);
    }
    return value;
}

function getConfig<T>(key: ConfigKeyType): T {
    if (Array.isArray(key)) {
        return getConfigKeyFromObject<T>(key[0], key[1]);
    }

    const value = config.get<T>(key);
    if (value === undefined) {
        throw new Error(`Missing config default value: ${CopilotConfigPrefix}.${key}`);
    }
    return value;
}

/**
 * Check whether the setting we got for a particular key
 * is still the default setting or has been overwritten
 * by a user setting (at any level).
 */
function isDefaultSettingOverwritten(key: typeof ConfigKey[keyof typeof ConfigKey]): boolean {
    if (Array.isArray(key)) {
        // This case mirrors getConfigKeyFromObject
        return (config[key[0]][key[1]] !== undefined);
    }
    const inspection = config.inspect(key);
    //return whether globalValue is defined
    return inspection ?
        !!inspection.globalValue ||
        !!inspection.workspaceValue ||
        !!inspection.workspaceFolderValue ||
        !!inspection.defaultLanguageValue ||
        !!inspection.globalLanguageValue ||
        !!inspection.workspaceLanguageValue ||
        !!inspection.workspaceFolderLanguageValue
        : false;
}

// Helper to avoid JSON.stringify quoting strings
function stringOrStringify(value: any) {
    if (typeof value === 'string') {
        return value;
    }
    return JSON.stringify(value);
}

// Dumps config settings defined in the extension json
function dumpConfig() {
    const configProperties: {[key: string]: string} = {};
    try {
        const extensionConfigProps = packageJson.contributes.configuration[0].properties;
        for (const key in extensionConfigProps) {
            const localKey = key.replace(`${CopilotConfigPrefix}.`, '');
            const value = localKey.split('.').reduce((o, i) => o[i], config);

            if (typeof value === 'object' && value !== null) {
                // Dump objects as their properties, filtering secret_key
                Object.keys(value)
                    .filter(k => k !== 'secret_key')
                    .forEach(k => configProperties[`${key}.${k}`] = stringOrStringify(value[k]));
            } else {
                configProperties[key] = stringOrStringify(value);
            }
        }
    } catch(ex) {
        // cannot use logger.error which makes a telemetry call
        console.error(`Failed to retrieve configuration properties ${ex}`);
    }
    return configProperties;
}

function getLanguageConfig<T>(key: ConfigKeyType, language?: string): T | undefined {
    const obj: {[key: string]: T} = getConfig(key);
    if (language === undefined && !process.env.IS_AGENT) {
        const editor = vscode.window.activeTextEditor;
        language = editor && editor.document.languageId;
    }
    return (language && language in obj) ? obj[language] : obj["*"];
}

export class VSCodeBlockModeConfig extends BlockModeConfig {
    forLanguage(ctx: Context, languageId: string): BlockMode {
        // If the user has explicitly overridden any indentation mode settings, use their settings
        // for all languages, regardless of any AB tests.
        // This is only likely to be our team as the setting is not advertised apart
        // from being discoverable in VSCode settings.
        if (isDefaultSettingOverwritten(ConfigKey.IndentationMode)) {
            const clientIndent = getLanguageConfig<"client"|"server"|boolean>(ConfigKey.IndentationMode, languageId);
            switch (clientIndent) {
                case "client":
                case true:
                    return BlockMode.Indentation;
                case "server":
                    return BlockMode.Server;
                default:
                    return BlockMode.Parsing;
            }
        }
        // For existing multiline languages use standard tree-sitter based parsing
        if (isSupportedLanguageId(languageId)) {
            switch (ABExperiments.treesitter_server_trimming_unbuffered.getGroup(ctx)) {
                case "server":
                    return BlockMode.Server;
                default:
                    return BlockMode.Parsing;
            }
        }
        // TODO: Issue #1210: lots of tests fail with BlockMode.Server. Move them to
        // the server or refactor them.
        if (inTestMode(ctx)) {
            return BlockMode.Indentation;
        }
        return BlockMode.Server;
    }
}


const vscodeConfigProvider: ConfigProvider = {
    getConfig: getConfig,
    isDefaultSettingOverwritten: isDefaultSettingOverwritten,
    dumpConfig: dumpConfig,
    getLanguageConfig: getLanguageConfig
}

export function registerConfigProvider() {
    setConfigProvider(vscodeConfigProvider);
}


export function updateEnabledConfig(language: string, global: boolean, enabled: boolean): Thenable<void> {
    const updatedConfig: {[key: string]: boolean} = getConfig(ConfigKey.Enable) || {};
    if (global && language in updatedConfig || !global) {
        updatedConfig[language] = enabled;
    }
    if (global) {
        updatedConfig["*"] = enabled;
    }
    return config.update(ConfigKey.Enable, updatedConfig, true);
}

export function setExtension(ext: vscode.Extension<any>) {
    extension = ext;
}

export function getExtension(ctx: Context): vscode.Extension<any> {
    if (!extension && inTestMode(ctx)) {
        // If in test mode we load the extension manually, since `extension.ts:activate` is not called
        extension = vscode.extensions.all.find(extension => extension.id.startsWith("GitHub.copilot"));
    }
    if (!extension) {
        throw new Error("No GitHub.copilot extension found");
    }
    return extension;
}

export function makeVscInfo(): VscInfo {
    return new VscInfo(vscode.env.sessionId, vscode.env.machineId, vscode.version);
}