import { comment } from "./languageMarker";
import { DocumentInfo, DocumentInfoWithOffset, NeighboringTabsOption } from "./prompt";
import { findBestJaccardMatch, ScoredSnippet } from "./selectRelevance";

interface NeighborSelection {
    windowLength: number;
    threshold: number;
    numberOfNeighbors: number;
}

const neighborOptionToSelection: Record<NeighboringTabsOption, NeighborSelection> = {
    none: {
        windowLength: 1,
        threshold: -1,
        numberOfNeighbors: 0
    },
    conservative: {
        windowLength: 10,
        threshold: 0.3,
        numberOfNeighbors: 1
    },
    medium: {
        windowLength: 20,
        threshold: 0.1,
        numberOfNeighbors: 2
    },
    eager: {
        windowLength: 60,
        threshold: 0,
        numberOfNeighbors: 4
    },
    eagerButLittle: {
        windowLength: 10,
        threshold: 0,
        numberOfNeighbors: 1
    },
};

// Sanity thresholds on the number of neighbors to consider
const MAX_CHARACTERS_PER_FILE = 10000;
const MAX_NUMBER_OF_FILES = 20;

/**
 * @returns A string describing the best matches from neighbors.
 */
export async function getNeighborSnippets(
    doc: DocumentInfoWithOffset,
    neighbors: DocumentInfo[],
    options: NeighboringTabsOption
): Promise<string[]> {
    const selection = neighborOptionToSelection[options];
    const truncatedDocument = {
        languageId: doc.languageId,
        source: doc.source
            .slice(0, doc.offset)
            .split("\n")
            .slice(-selection.windowLength)
            .join("\n"),
    };
    return (
        neighbors
            // filter out absurdly long or absurdly many open files
            .filter(neighbor => neighbor.source.length < MAX_CHARACTERS_PER_FILE && neighbor.source.length > 0)
            .slice(0, MAX_NUMBER_OF_FILES)
            // compute the similarity for each
            .map(neighbor =>
                ({ path: neighbor.path, ...findBestJaccardMatch(neighbor, truncatedDocument, selection.windowLength) })
            )
            .filter(neighbor =>
                // remove files that had no match at all
                neighbor.score && neighbor.snippet &&
                // remove files that had a low score
                neighbor.score > selection.threshold
            ) as
        // assert that score and neigbor are defined (or they'd have been removed abvoe)
        ScoredSnippet[]
    )
        // order them with best (highest scores) last
        .sort((a, b) => a.score - b.score)
        // take the best options from the end
        .slice(-selection.numberOfNeighbors)
        // describe each one of them and split in lines
        .map(announceSnippet)
        // now for each snippet:
        .map(snippet => snippet
            // comment out each line
            // FIXME: possibly want to use multi-line comments, either per snippet or one big one
            .map(line => comment(line, doc.languageId) + "\n")
            // join them
            .join("")
        );
}

function announceSnippet(snippet: ScoredSnippet): string[] {
    return [snippet.path ?
        "Compare this snippet from " + snippet.path + ":" :
        "Compare this snippet:"
    ].concat(snippet.snippet.split("\n"));
}