import { DocumentInfoWithOffset, newLineEnded } from "./prompt";
import { parseTree,
    isSupportedLanguageId,
    getAncestorWithSiblingFunctions,
    isFunctionDefinition,
    getFirstPrecedingComment } from './parse';

/**
 * Finds the sibling functions to the given offset in the source code.
 *
 * @param documentInfo The document description
 *         (of which source text, offset and language will be used)
 * @returns A triple { siblings, beforeInsertion, afterInsertion }:
 *          * a list of sibling functions (as strings)
 *          * the part of the source before the siblings should be inserted
 *          * the part of the source after the siblings should be inserted,
 *            but only up to the cursor offset.
 */
 export async function getSiblingFunctions({source, offset, languageId} : DocumentInfoWithOffset) {
    // if we can't process, then there's no siblings and everything is the ancestor
    const siblings: string[] = [];
    let beforeInsertion = "";
    let afterInsertion = source.substring(0, offset);

    if(isSupportedLanguageId(languageId)) {
        const tree = await parseTree(languageId, source);
        try {
            // find syntax-tree node we are on or right after
            let startingOffset = offset;
            while (startingOffset >= 0 && /\s/.test(source[startingOffset]))
                startingOffset--;
            const nd = tree.rootNode.descendantForIndex(startingOffset);

            // find the closest ancestor that may have sibling functions
            const anc = getAncestorWithSiblingFunctions(languageId, nd);
            if (anc) {
                // we want to insert the siblings right before that ancestor, or its
                // doc comment if there is one (note that we treat all preceding comments
                // as potentially interesting, even for Python)
                const ancDocComment = getFirstPrecedingComment(anc);
                const insertionPoint = ancDocComment?.startIndex ?? anc.startIndex;

                // record indentation of the ancestor; we need to restore it later
                let indentLength = 0, c;
                while ((c = source[insertionPoint - indentLength - 1]) == ' ' || c == '\t') {
                    indentLength++;
                }
                const indentStr = source.substring(insertionPoint - indentLength, insertionPoint);

                // find sibling functions and include them all
                for (let sibling = anc.nextSibling; sibling; sibling = sibling.nextSibling) {
                    if (isFunctionDefinition(languageId, sibling)) {
                        // take `sibling`, as well as any comments immediately preceding it, but not if
                        // it precedes or spans `offset`
                        const docComment = getFirstPrecedingComment(sibling);
                        const startIndex = docComment?.startIndex ?? sibling.startIndex;
                        if (startIndex < offset) {
                            continue;
                        }

                        const siblingText = source.substring(startIndex, sibling.endIndex);
                        const newText = newLineEnded(siblingText) + '\n' + indentStr;

                        siblings.push(newText);
                    }
                }

                beforeInsertion = source.substring(0, insertionPoint);
                afterInsertion = source.substring(insertionPoint, offset);
            }
        } finally {
            tree.delete();
        }
    }
    return { siblings, beforeInsertion, afterInsertion };
}