export async function* asyncIterableMap<TSource, TDest>(
    source: AsyncIterable<TSource>,
    selector: (x: TSource) => Promise<TDest>): AsyncIterable<TDest> {
    for await (const item of source) {
        yield selector(item);
    }
}

export async function* asyncIterableFilter<TSource>(
    source: AsyncIterable<TSource>,
    predicate: (x: TSource) => Promise<boolean>): AsyncIterable<TSource> {
    for await (const item of source) {
        if (await predicate(item)) {
            yield item;
        }
    }
}

export async function* asyncIterableMapFilter<TSource, TDest>(
    source: AsyncIterable<TSource>,
    selector: (x: TSource) => Promise<TDest | undefined>): AsyncIterable<TDest> {
    for await (const item of source) {
        const result = await selector(item);
        if (result !== undefined) {
            yield result;
        }
    }
}

export async function* asyncIterableFromArray<TSource>(
    source: TSource[]): AsyncIterable<TSource> {
    for (const item of source) {
        yield item;
    }
}
