import {
    createMessageConnection,
    MessageConnection,
    StreamMessageReader,
    StreamMessageWriter,
    CancellationToken,
    ResponseError,
} from 'vscode-jsonrpc/node';
import { Context } from '../../lib/src/context';
import { init } from './init';
import { MethodHandlers } from './methods/methods';
import { ErrorCode } from './rpc';

export class CopilotService {
    public constructor(private readonly ctx: Context, private readonly connection: MessageConnection) {
        connection.onRequest(this.messageHandler.bind(this));
    }

    private async messageHandler(method: string, params: any[] | object | undefined, token: CancellationToken): Promise<any | ResponseError<any>> {
        const handler = this.ctx.get(MethodHandlers).handlers.get(method);
        if (!handler) {
            return {
                code: ErrorCode.MethodNotFound,
                message: `Method not found: '${method}'`
            };
          }

        // TODO figure out what's going on here
        if (Array.isArray(params)) {
            params = params[0];
        }
        const [maybeResult, maybeErr] = await handler(this.ctx, params);
        if (maybeErr) {
            // What we return needs to satisfy `instanceof ResponseError` to be treated as an error by vscode-jsonrpc.
            const responseError =
              new ResponseError<any>(maybeErr.code, maybeErr.message, maybeErr.data);
            return responseError;
        } else {
            return maybeResult;
        }
    }

    public listen() {
        this.connection.listen();
    }
}

export function CreateCopilotService(stream: NodeJS.ReadWriteStream) {
    const ctx = init();
    let connection = createMessageConnection(
        new StreamMessageReader(stream),
        new StreamMessageWriter(stream));

    const service = new CopilotService(ctx, connection);

    service.listen();
}