import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { Context } from '../../../lib/src/context';
import { getVersion } from '../../../lib/src/config';

export type Params = {};
export type Result = {
    version: string;
};

const paramsSchema = {
  type: 'object'
};

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

export default async function handleGetVersion(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
  if (validParams(params)) {
    return [{
      version: getVersion()
    }, null];
  } else {
    const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
    return [null, {
      code: ErrorCode.InvalidParams,
      message: 'Invalid params: ' + errorMessages.join(';')
    }];
  }
}
