import {
    ExtensionContext,
    Position,
    TextDocument,
} from 'vscode';
import * as vscode from 'vscode';
import TelemetryReporter from 'vscode-extension-telemetry';
import { getConstantExperimentGroups } from '../../extension/src/abexperiments';
import { getExtension } from '../../extension/src/config';
import { inTestMode } from './testing/testMode';
import { APIJsonData, RequestId } from './openai/openai';
import Ajv, { JSONSchemaType } from 'ajv';
import { dumpConfig, getVersion } from './config';
import { Context } from './context';

// the application insights key (also known as instrumentation key)
const APP_INSIGHTS_KEY = '7d7048df-6dd0-4048-bb23-b716c1461f8f';        // copilot-telemetry under github non-prod octo
const APP_INSIGHTS_KEY_SECURE = '3fdd7f28-937a-48c8-9a21-ba337db23bd1';  // copilot-telemetry-secure under github prod copilot

// telemetry reporter
let reporter: TelemetryReporter | undefined;
// telemetry reporter for secure context
let reporterSecure: TelemetryReporter | undefined;

// tracking id from auth token
let copilotTrackingId: string;
export { copilotTrackingId };

// Override user opt-in config namespace to check "copilot.enableTelemetry"
TelemetryReporter['TELEMETRY_CONFIG_ID'] = "copilot";

type TelemetryProperties = { [key: string]: string };
const propertiesSchema: JSONSchemaType<TelemetryProperties> = {
    type: 'object',
    additionalProperties: {
        type: 'string'
    },
    required: []
};
type TelemetryMeasurements = { [key: string]: number };
const measurementsSchema: JSONSchemaType<TelemetryMeasurements> = {
    type: 'object',
    properties: {
        meanLogProb: { type: 'number', nullable: true },
        meanAlternativeLogProb: { type: 'number', nullable: true },
    },
    additionalProperties: {
        type: 'number'
    },
    required: []
};

/**
 * A class holding the data we want send to telemetry,
 * {@link TelemetryData.properties} containing the strings
 * and {@link TelemetryData.measurements} containing the numbers.
 *
 * Additionally, this keeps tracks of timestamps {@link TelemetryData.created} and {@link TelemetryData.displayed}
 * that can be used to track when this object was created or when information
 * contained in this object was surfaced to the user.
 *
 * This is meant be used as an argument to
 * {@link telemetry}, {@link telemetryError}, or {@link telemetryException}.
 */
export class TelemetryData {
    properties: TelemetryProperties;
    measurements: TelemetryMeasurements;
    issuedTime: number;
    displayedTime?: number;

    private static ajv = new Ajv({strictNumbers: false});
    private static validateTelemetryProperties = TelemetryData.ajv.compile(propertiesSchema);
    private static validateTelemetryMeasurements = TelemetryData.ajv.compile(measurementsSchema);

    private constructor(properties: { [key: string]: string }, measurements: { [key: string]: number }, issuedTime: number) {
        this.properties = properties;
        this.measurements = measurements;
        this.issuedTime = issuedTime;
    }

    static createAndMarkAsIssued(properties?: { [key: string]: string },
                                 measurements?: { [key: string]: number }): TelemetryData {
        return new TelemetryData(properties || {}, measurements || {}, now());
    }

    /**
     * @param properties new properties, which will overwrite old ones in case of a clash
     * @param measurements new measurements, which will overwrite old ones in case of a clash
     * @returns a TelemetryData object whose contents extend (copies of) the current one's and whose creation date is not updated
     */
    extendedBy(properties?: { [key: string]: string }, measurements?: { [key: string]: number }): TelemetryData {
        const newProperties = {...this.properties, ...properties};
        const newMeasurements = {...this.measurements, ...measurements};
        const newData = new TelemetryData(newProperties, newMeasurements, this.issuedTime);
        newData.displayedTime = this.displayedTime;

        return newData;
    }

    /**
     * registers current time as the point where this was displayed
     * (no-op if a display time is already registered)
     */
    markAsDisplayed(): void {
        if (this.displayedTime === undefined){
            this.displayedTime = now();
        }
    }

    extendWithABExperimentGroups(ctx: Context): void {
        const groups = getConstantExperimentGroups(ctx);
        if (groups) {
            this.properties['experimentGroups'] = JSON.stringify(groups);
        }
    }

    extendWithEditorAgnosticFields(): void {
        // These duplicate some of the standard fields VSCode inserts, but it's
        // worth it to have consistency across different clients and the proxy.
        if (process.env.IS_AGENT) {
            this.properties['agent_version'] = `agent/${getVersion()}`;
        } else {
            // TODO these two should come from the actual plugin when we're in agent mode.
            this.properties['editor_version'] = `vscode/${vscode.version}`;
            this.properties['editor_plugin_version'] = `copilot/${getVersion()}`;

            this.properties['client_machineid'] = vscode.env.machineId;
            this.properties['client_sessionid'] = vscode.env.sessionId;
        }
    }
    /**
     * Iterate config keys defined in the package.json, lookup current config
     * value and return as telemetry property. Property name in dotted notation
     * and value is a json string.
     * e.g. { 'copilot.autocompletion.count': 3 }
     */
    extendWithConfigProperties(ctx: Context): void {
        const configProperties: { [key: string]: string } = dumpConfig();

        // Add build fields from package.json
        try {
            const extension = getExtension(ctx);
            configProperties['copilot.build'] = extension.packageJSON.build;
            configProperties['copilot.buildType'] = extension.packageJSON.buildType;

            // TODO(drifkin): once we've figured out the agent build, we should
            // probably add properties here to indicate what kind of build it is
        } catch (ex) {
            // ignore getExtension exception if extension is not initialized
        }

        if (copilotTrackingId) {
            configProperties['copilot.trackingId'] = copilotTrackingId;
        }

        // By being the second argument, configProperties will always override
        this.properties = {...this.properties, ...configProperties};
    }

    extendWithRequestId(requestId: RequestId): void {
        const requestProperties = {
            completionId: requestId.completionId,
            headerRequestId: requestId.headerRequestId,
            serverExperiments: requestId.serverExperiments,
            proxyRole: requestId.proxyRole,
            modelEndpoint: requestId.modelEndpoint,
        };
        this.properties = {...this.properties, ...requestProperties};
    }

    sanitizeKeys(): void {
        this.properties = TelemetryData.sanitizeKeys(this.properties);
        this.measurements = TelemetryData.sanitizeKeys(this.measurements);
    }

    static sanitizeKeys(map?: { [key: string]: any }): { [key: string]: any } {
        // We need all keys to not have dots in them for telemetry to function
        map = map || {};
        const returnValue: { [key: string]: any } = {};
        // Iterate over all keys in the map and replace dots with underscores
        for (const key in map) {
            returnValue[key.replace(/\./g, '_')] = map[key];
        }
        return returnValue;
    }

    updateTimeSinceIssuedAndDisplayed(): void {
        const timeSinceIssued = now() - this.issuedTime;
        this.measurements.timeSinceIssuedMs = timeSinceIssued;

        if (this.displayedTime !== undefined) {
            const timeSinceDisplayed = now() - this.displayedTime;
            this.measurements.timeSinceDisplayedMs = timeSinceDisplayed;
        }
    }

    /** Validate that the data of the telemetry is in a valid format, i.e. that
     *  all values of `properties` are strings and all values of `measurements` are
     *  numbers.
     */
    validateData(ctx: Context, secure: boolean): boolean {
        let invalid: undefined | { problem: string, error: string };
        if (!TelemetryData.validateTelemetryProperties(this.properties)) {
            invalid = {
                problem: "properties",
                error: JSON.stringify(TelemetryData.validateTelemetryProperties.errors),
            }
        }
        if (!TelemetryData.validateTelemetryMeasurements(this.measurements)) {
            const m_err = JSON.stringify(TelemetryData.validateTelemetryMeasurements.errors);
            if (invalid === undefined) {
                invalid = {
                    problem: "measurements",
                    error: m_err,
                }
            } else {
                invalid.problem = "both";
                invalid.error += `; ${m_err}`;
            }
        }
        if (invalid === undefined) {
            return true;
        } else {
            if (inTestMode(ctx)) {
                throw new Error(`Invalid telemetry data: ${invalid.problem} ${invalid.error} properties=${JSON.stringify(this.properties)} measurements=${JSON.stringify(this.measurements)}`);
            }
            telemetryError(ctx, "invalidTelemetryData", TelemetryData.createAndMarkAsIssued({
                'properties': JSON.stringify(this.properties),
                'measurements': JSON.stringify(this.measurements),
                'problem': invalid.problem,
                'validationError': invalid.error
            }), secure );
            if (secure) {
                // We cannot post the full telemetry event to the secure, but we
                // can flag on the insecure that there has been an event logged
                // to the secure, making it easier to discover.
                telemetryError(ctx, "invalidTelemetryData_in_secure", TelemetryData.createAndMarkAsIssued({
                    'problem': invalid.problem,
                    'requestId': this.properties['requestId'] ?? "unknown"
                }), false );
            }
            return false;
        }
    }

    makeReadyForSending(ctx: Context, secure: boolean): void {
        this.extendWithConfigProperties(ctx);
        this.extendWithEditorAgnosticFields();
        this.extendWithABExperimentGroups(ctx);
        this.sanitizeKeys();
        this.updateTimeSinceIssuedAndDisplayed();
        if (!this.validateData(ctx, secure)) {
            // There's some problem with the data, but try to send it regardless with an extra
            // property we can filter for. There's a risk that the underlying telemetry library will just
            // silently drop it, though.
            this.properties['telemetry_failed_validation'] = 'true';
        }
    }
}

// Helpers

export function ghostTextTelemetry(document: TextDocument,
                                      position: Position,
                                      prefix: string,
                                      lineBeforeCursor: string,
                                      restOfLine: string): TelemetryData {
    const properties: { [key: string]: string } = {
        "languageId": document.languageId,
        "beforeCursorWhitespace": JSON.stringify(lineBeforeCursor.trim() === ''),
        "afterCursorWhitespace": JSON.stringify(restOfLine.trim() === ''),
    };
    const measurements: { [key: string]: number } = {
        "promptCharLen": prefix.length,
        "promptEndPos": document.offsetAt(position),
        "documentLength": document.getText().length,
    };
    return TelemetryData.createAndMarkAsIssued(properties, measurements);
}

export function now(): number {
    return new Date().getTime();
}

export function sleep(ms: number): Promise<void> {
    // This function will return a promise that will sleep for ms milliseconds
    return new Promise(resolve => setTimeout(resolve, ms));
}

function setupReporter(extensionId: string, extensionVersion: string, key: string) {
    const reporter = new TelemetryReporter(extensionId, extensionVersion, key);

    // @ts-ignore - ignore private members
    if (!reporter.appInsightsClient) {
        // @ts-ignore - ignore private members
        reporter.userOptIn = true;
        // @ts-ignore - ignore private members
        reporter.createAppInsightsClient(key);
    }

    // @ts-ignore - ignore private members
    if (reporter.appInsightsClient) {
        // @ts-ignore - ignore private members
        const existingProperties = reporter.appInsightsClient.commonProperties;

        // In order to query common properties with azure monitor and grafana,
        // we need to replace `.' with '_' in the properties key.
        // NOTE: We do not do this in a single line to avoid errors in sanitizing from being swallowed.
        const sanitizedProperties = TelemetryData.sanitizeKeys(existingProperties);

        // @ts-ignore - ignore private members
        reporter.appInsightsClient.commonProperties = sanitizedProperties;

        // Do not want personal machine names to be sent
        // @ts-ignore - ignore private members
        reporter.appInsightsClient.context.tags[reporter.appInsightsClient.context.keys.cloudRoleInstance] = "REDACTED";
    }

    return reporter;
}

export function setupAgentReporters() {
    const extensionId = 'agent';
    const extensionVersion = getVersion();
    reporter = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY);
    reporterSecure = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY_SECURE);
}

export function activate(context: ExtensionContext) {
    const extension = context.extension;
    const extensionId = extension.packageJSON.name;
    const extensionVersion = getVersion();

    // create telemetry reporter on extension activation
    reporter = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY);
    reporterSecure = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY_SECURE);

    // ensure it gets property disposed
    context.subscriptions.push(reporter);
    context.subscriptions.push(reporterSecure);
}

export function deactivate() {
    // This will ensure all pending events get flushed
    if (reporter) {
        reporter.dispose();
        reporter = undefined;
    }
    if (reporterSecure) {
        reporterSecure.dispose();
        reporterSecure = undefined;
    }
}

export function telemetry(
    ctx: Context,
    name: string,
    telemetryData?: TelemetryData,
    secure?: boolean
) {
    // if telemetry data isn't given, make a new one to hold at least the config
    telemetryData = telemetryData || TelemetryData.createAndMarkAsIssued({}, {});
    telemetryData.makeReadyForSending(ctx, secure ?? false);
    const r = secure ? reporterSecure : reporter;
    r && r.sendTelemetryEvent(name, telemetryData.properties, telemetryData.measurements);
}

export function telemetryException(
    ctx: Context,
    maybeError: unknown,
    telemetryData?: TelemetryData
) {
    let error = maybeError instanceof Error ? maybeError : new Error('Non-error thrown: ' + maybeError);
    telemetryData = telemetryData || TelemetryData.createAndMarkAsIssued({}, {});
    telemetryData.makeReadyForSending(ctx, false);
    reporter && reporter.sendTelemetryException(error, telemetryData.properties, telemetryData.measurements);
}

export function telemetryError(
    ctx: Context,
    name: string,
    telemetryData?: TelemetryData,
    secure?: boolean
) {
    telemetryData = telemetryData || TelemetryData.createAndMarkAsIssued({}, {});
    telemetryData.makeReadyForSending(ctx, secure ?? false);
    const r = secure ? reporterSecure : reporter;
    r && r.sendTelemetryErrorEvent(name, telemetryData.properties, telemetryData.measurements);
}

export function logEngineCompletion(ctx: Context, completionText: string, jsonData: APIJsonData, requestId: RequestId, choiceIndex: number) {
    const telemetryData = TelemetryData.createAndMarkAsIssued({
        completionTextJson: JSON.stringify(completionText),
        choiceIndex: choiceIndex.toString(),
    });

    for (const [key, value] of Object.entries(jsonData.logprobs)) {
        telemetryData.properties["logprobs_" + key] = JSON.stringify(value) ?? "unset";
    }

    telemetryData.extendWithRequestId(requestId);
    telemetry(ctx, "engine.completion", telemetryData, true /*secure*/);
}

export function logEnginePrompt(ctx: Context, prompt: string, telemetryData: TelemetryData) {
    const telemetryDataWithPrompt = telemetryData.extendedBy({
        promptJson: JSON.stringify(prompt)
    });
    telemetry(ctx, "engine.prompt", telemetryDataWithPrompt, true /*secure*/);
}

export function setTrackingId(trackingId: string) {
    copilotTrackingId = trackingId;
}
