import { Console } from 'console';
import { OutputChannel } from 'vscode';
import { TelemetryData, telemetryError } from './telemetry';
import { ConfigKeyType, isProduction, getConfig, ConfigKey } from './config';
import { Context } from './context';

const COPILOT_AGENT_VERBOSE = 'COPILOT_AGENT_VERBOSE';

export enum LogLevel {
    DEBUG = 0,
    INFO = 1,
    WARN = 2,
    ERROR = 3,
}

let output: OutputChannel | undefined;
export function setOutputChannel(outputChannel?: OutputChannel) {
    output = outputChannel;
}

export interface LoggerInterface {
    debug(ctx: Context, msg: string, ...extra: any[]): void;
    info(ctx: Context, msg: string, ...extra: any[]): void;
    warn(ctx: Context, msg: string, ...extra: any[]): void;
    error(ctx: Context, msg: string, ...extra: any[]): void;

    setLevel(level: LogLevel): void;
}

interface Console {
    log(...args: any[]): void;
    warn(...args: any[]): void;
    error(...args: any[]): void;
}

class Clock {
    public timestampString(): string {
        return (new Date()).toISOString();
    }
}

/** For use in tests, to wire through fake implementations of dependencies. */
export interface Overrides {
    output?: OutputChannel;
    console?: Console,
    clock?: Clock,
    isProduction?: () => boolean,
    getConfig?: <T> (key: ConfigKeyType) => T,
}

export class Logger implements LoggerInterface {
    minLoggedLevel: LogLevel;
    context: string;
    private outputOverride: OutputChannel | undefined;
    private console: Console;
    private clock: Clock;
    private isProduction: () => boolean;
    private getConfig: <T> (key: ConfigKeyType) => T;

    constructor(minLoggedLevel: LogLevel, context: string, overrides?: Overrides) {
        this.minLoggedLevel = minLoggedLevel;
        this.context = context;
        this.outputOverride = overrides?.output;
        this.console = overrides?.console ?? console;
        this.clock = overrides?.clock ?? new Clock();
        this.isProduction = overrides?.isProduction ?? isProduction;
        this.getConfig = overrides?.getConfig ?? getConfig;
    }

    public setLevel(level: LogLevel) {
        this.minLoggedLevel = level;
    }

    private stringToLevel(s: string|undefined): LogLevel|undefined {
        return LogLevel[s as keyof typeof LogLevel];
    }

    private log(ctx: Context, level: LogLevel, secure: boolean, ...extra: any[]) {
        let logFn = undefined;
        const levelString = LogLevel[level];

        if (level == LogLevel.ERROR) {
            logFn = this.console.error.bind(this.console);

            telemetryError(ctx, "log", TelemetryData.createAndMarkAsIssued({
                'context': this.context,
                'level': levelString,
                'message': extra.length > 0 ? JSON.stringify(extra) : "no msg",
            }), secure);
        } else if (level == LogLevel.WARN) {
            logFn = this.console.warn.bind(this.console);
        } else {
            // Don't log INFO or DEBUG messages into console. They are still logged in the output channel.
            logFn = () => {};
        }

        // TODO(drifkin): temporarily putting in a "please log everything to
        // stderr" mode for agent<->neovim debugging. We should build something
        // nicer soon that reconciles the output channel (which doesn't exist in
        // the agent) and console split, but this will help a lot in the
        // meantime
        const agentVerbose = process.env.IS_AGENT && this.isAgentVerboseSet();
        if (agentVerbose) {
            logFn = this.console.error.bind(this.console);
        }

        if (!this.shouldLog(level, this.context) && !agentVerbose) {
            return;
        }
        // Generate timezone aware timestamp
        const timestamp = this.clock.timestampString();
        logFn(
            `[${levelString}] [${this.context}] [${timestamp}]`
            , ...extra
        );
        const maybeOutput = this.outputOverride ?? output;
        if (maybeOutput) {
            maybeOutput.appendLine(`[${levelString}] [${this.context}] [${timestamp}] ${extra.map(toPlainText)}`);
        }
    }

    private isAgentVerboseSet() {
        if (COPILOT_AGENT_VERBOSE in process.env) {
            const val = process.env[COPILOT_AGENT_VERBOSE];
            return val === '1' || val === 'true';
        }
        return false;
    }

    private shouldLog(level: LogLevel, category: string): boolean {
        let levels = this.getConfig<string[]>(ConfigKey.DebugFilterLogCategories)
        //If any config is set, show only the configured categories
        if (levels.length > 0 && !levels.includes(category)) {
            return false;
        }

        if (this.isProduction()) {
            return level >= this.minLoggedLevel;
        }
        // In dev builds, take log level override user pref into account.
        const overrides = this.getConfig<{[context: string]: string}>(ConfigKey.DebugOverrideLogLevels);
        const minLevel = this.stringToLevel(overrides['*'])
            ?? this.stringToLevel(overrides[this.context])
            ?? this.minLoggedLevel;
        return level >= minLevel;
    }

    public debug(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.DEBUG, false /*not secure*/, ...extra);
    }

    public info(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.INFO, false /*not secure*/, ...extra);
    }

    public warn(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.WARN, false /*not secure*/, ...extra);
    }

    public error(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.ERROR, false /*not secure*/, ...extra);
    }

    /**
     * Secure errors will have their extra data logged to secure telemetry,
     * and only their category logged to standard telemetry.
     */
    public secureError(ctx: Context, category: string, ...extra: any[]) {
        this.log(ctx, LogLevel.ERROR, false /*not secure*/, category);
        this.log(ctx, LogLevel.ERROR, true /*secure*/, category, ...extra);
    }
}

function toPlainText(x: unknown): string {
    switch (typeof x) {
        case 'object':
            return JSON.stringify(x);
        default:
            return String(x);
    }
}

export const logger = new Logger(LogLevel.INFO, "default");
