import * as util from 'util';
import * as fetchH2 from 'fetch-h2';
import * as uuid from 'uuid';
import { telemetry, TelemetryData } from './telemetry';
import { VscInfo } from './config';
import { Context } from './context';
import { ICancellationToken } from './cancellation';

export type Response = fetchH2.Response;

let initialized = false;
let version: string;

// initialize the default H2 context user-agent
export function init(copilotVersion: string) {
    if (initialized) {
        if (copilotVersion !== version) {
            throw new Error(
                `Networking re-initialized with mismatched version (old: ${version}, new: ${copilotVersion})`
            );
        }
        // it is undefined behavior to call fetchH2.setup more than once
        return;
    }
    version = copilotVersion;
    // TODO(drifkin): remove fetchH2.setup entirely post-universe (and also this
    // whole init function)
    if (!process.env.IS_AGENT) {
        fetchH2.setup({
            userAgent: `GithubCopilot/${copilotVersion}`,
            overwriteUserAgent: true,
        });
    }
    initialized = true;
}

// The maximum time to wait for a request to complete.
const requestTimeoutMs = 30 * 1000; // 30 seconds

export function postRequest(
    ctx: Context,
    url: string,
    secretKey: string,
    intent: string | undefined,  // Must be passed in, even if explicitly `undefined`
    vscInfo: VscInfo,
    body?: Record<string, any>,
    cancelToken?: ICancellationToken): Promise<Response>
{
    if (!initialized) {
        throw new Error('Networking must be initialized before being used');
    }

    const requestId = uuid.v4();
    const headers: {[key: string]: string} = {
        'Authorization': util.format('Bearer %s', secretKey),
        'X-Request-Id': requestId,
        'Openai-Organization': 'github-copilot',
        'VScode-SessionId': vscInfo.sessionId,
        'VScode-MachineId': vscInfo.machineId,
        'Editor-Version': 'vscode/'+vscInfo.vsCodeVersion,
        'Editor-Plugin-Version': 'copilot/'+version
    };
    if (intent) {
        headers['OpenAI-Intent'] = intent;
    }

    const request: any = {
        method: 'POST',
        headers: headers,
        json: body,
        timeout: requestTimeoutMs,
    };

    if (cancelToken) {
        const abort = new fetchH2.AbortController();
        cancelToken.onCancellationRequested(() => {
            // abort the request when the token is canceled
            telemetry(ctx, 'networking.cancelRequest', TelemetryData.createAndMarkAsIssued({ headerRequestId: requestId }));
            abort.abort();
        });
        // pass the controller abort signal to the request
        request.signal = abort.signal;
    }

    const requestPromise = fetchH2
        .fetch(url, request)
        .catch(reason => {
            if (reason.code == "ECONNRESET" ||
                reason.code == "ETIMEDOUT" ||
                reason.code == "ERR_HTTP2_INVALID_SESSION" ||
                reason.message == "ERR_HTTP2_GOAWAY_SESSION")
            {
                // disconnect and retry the request once if the connection was reset
                telemetry(ctx, 'networking.disconnectAll');
                return fetchH2.disconnectAll().then(() => {
                    return fetchH2.fetch(url, request);
                });
            } else {
                throw reason;
            }
        });
    return requestPromise;
}
