import { ConfigKey, ConfigKeyType, ConfigProvider, getConfigDefaultForKey, getConfigDefaultForObjectKey, setConfigProvider } from "../../lib/src/config";

function getConfig<T>(key: ConfigKeyType): T {
    // hardcode default values for the agent, for now
    if (Array.isArray(key)) {
        return getConfigDefaultForObjectKey<T>(key[0], key[1]);
    } else {
        return getConfigDefaultForKey<T>(key);
    }
}

function isDefaultSettingOverwritten(key: typeof ConfigKey[keyof typeof ConfigKey]): boolean {
    return false;
}

function dumpConfig() {
    // TODO(drifkin): the agent can't override any defaults yet, but
    // dumpConfig() provides a subset of defaults, so an empty object
    // wouldn't match the extension behavior. Giving a hint to anyone
    // looking at events in kusto that this isn't implemented.
    return {
        AGENT_DUMP_CONFIG_UNIMPLMEMENTED: ''
    };
}

function getLanguageConfig<T>(key: ConfigKeyType, language?: string): T | undefined {
    const obj: {[key: string]: T} = getConfig(key);
    return (language && language in obj) ? obj[language] : obj["*"];
}

const agentConfigProvider: ConfigProvider = {
    getConfig: getConfig,
    isDefaultSettingOverwritten: isDefaultSettingOverwritten,
    dumpConfig: dumpConfig,
    getLanguageConfig: getLanguageConfig,
}

export function registerConfigProvider() {
    setConfigProvider(agentConfigProvider);
}