
import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { AuthStatus, AuthManager } from '../auth/manager';
import { Context } from '../../../lib/src/context';

export type Params = {
    options?: {}
};

const paramsSchema = {
    type: 'object',
    properties: {
      options: {
          type: 'object',
          required: [],
          properties: {
          }
        },
      }
};

export type Result = AuthStatus;

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

/** The `signInConfirm` method should be called after receiving a `PromptUserDeviceFlow` response from `initiateSignIn` and
 *  actually prompting the user as described in the `Result` type for `initiateSignIn`.
 *
 *  It will not return a result until the user signs in or the attempt times out.
 *
 *  The result will be an `AuthStatus` object either indicating that the user is now fully authenticated,
 *  or that some other problem remains. A common response will be `NoTelemetryConsent` as typically this is only
 *  gathered after the user signs in.
 */
export default async function handleSignInConfirm(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
    if (validParams(params)) {
        const pendingSignIn = ctx.get(AuthManager).getPendingSignIn();
        if (pendingSignIn === undefined) {
            return [null, {
                code: ErrorCode.InvalidRequest,
                message: 'No pending sign in'
            }];
        }
        let result;
        try {
            result = await pendingSignIn;
            return [result, null];
        } catch(err: any) {
            return [null, {
                code: ErrorCode.DeviceFlowFailed,
                message: err.toString()
            }];
        } finally {
            ctx.get(AuthManager).setPendingSignIn(undefined);
        }
    } else {
          const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
          return [null, {
            code: ErrorCode.InvalidParams,
            message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}
