import { Logger, LogLevel } from "../logger";
import { fetch } from 'fetch-h2';
import { TelemetryData, telemetry, telemetryError, setTrackingId } from "../telemetry";
import { Context } from "../context";

const authLogger = new Logger(LogLevel.INFO, "auth");

const GITHUB_API_COPILOT_TOKEN_URL = 'https://api.github.com/copilot_internal/token';

export function nowSeconds(): number {
    return Math.floor(Date.now() / 1000);
}

export interface TokenInfo {
    token: string,     // tracking_id:unix_time:mac
    expires_at: number // unix time UTC in seconds
}

export type TokenErrorReason = "NotAuthorized" | "FailedToGetToken" | "TokenInvalid" | "GitHubLoginFailed";

export type TokenError = {
    reason: TokenErrorReason,
    message?: string // TODO: not used yet, but will be for 466 errors
}

export type TokenInfoOrError =
  | { kind: "success" } & TokenInfo
  | { kind: "failure" } & TokenError

type NotGitHubLoginFailed = { kind: "success" } | { kind: "failure", reason: Exclude<TokenErrorReason, "GitHubLoginFailed"> };

export async function authFromGitHubToken(ctx: Context, githubToken: string): Promise<TokenInfoOrError & NotGitHubLoginFailed> {
    telemetry(ctx, "auth.new_login");

    // Get the copilot token for accessToken
    const response = await fetch(GITHUB_API_COPILOT_TOKEN_URL, {
        headers: {
            'Authorization': `token ${githubToken}`
        }
    });
    if (!response) {
        authLogger.info(ctx, "Failed to get copilot token");
        telemetryError(ctx, "auth.request_failed");
        return { kind: "failure", reason: "FailedToGetToken" };
    }

    // FIXME: Unverified type after inputting response
    const tokenInfo: undefined | TokenInfo = await response.json();
    if (!tokenInfo) {
        authLogger.info(ctx, "Failed to get copilot token");
        telemetryError(ctx, "auth.request_read_failed");
        return { kind: "failure", reason: "FailedToGetToken" };
    }

    if (!response.ok || !tokenInfo.token) {
        authLogger.info(ctx, `Invalid copilot token: missing token: ${response.status} ${response.statusText}`);
        telemetryError(ctx, "auth.invalid_token", TelemetryData.createAndMarkAsIssued({
            status: response.status.toString(),
            status_text: response.statusText
        }));
        return { kind: "failure", reason: "NotAuthorized" };
    }

    const now = nowSeconds();
    if (!(tokenInfo.expires_at > now)) {
        authLogger.info(ctx, `Invalid copilot token: invalid expires_at:${tokenInfo.expires_at} now:${now}`);
        telemetryError(ctx, "auth.invalid_expires_at", TelemetryData.createAndMarkAsIssued({
            expires_at: JSON.stringify(tokenInfo.expires_at) ?? "undefined",
            now: now.toString()
        }));
        return { kind: "failure", reason: "FailedToGetToken" };
    }

    const token = tokenInfo.token;

    // set tracking id for telemetry reporting
    setTrackingIdFromToken(token);

    telemetry(ctx, "auth.new_token");

    return { kind: "success", ...tokenInfo };
}

export function setTrackingIdFromToken(token: string) {
    const trackingId = token?.split(':')[0];
    if (trackingId) {
        setTrackingId(trackingId);
    }
}


export abstract class CopilotTokenManager {
    /** Return a currently valid Copilot token, retrieving a fresh one if
     *  necessary.
     *
     *  Note that a Copilot token manager should not provide a Copilot token unless
     *  telemetry consent has been obtained. If this is not checked by the token manager
     *  implementation itself, then anything constructing or initialising it should not
     *  do so without checking this.
     */
    abstract getCopilotToken(ctx: Context): Promise<string>;

    /** Drop the current Copilot token as we received an HTTP error while trying
     *  to use it that indicates it's no longer valid.
     */
    abstract resetCopilotToken(ctx: Context, httpError: number): void;
}

/**
 * A `CopilotTokenManager` that always returns the same token.
 * Mostly only useful for short periods, e.g. tests or single completion requests,
 * as these tokens typically expire after a few hours.
 */
export class FixedCopilotTokenManager extends CopilotTokenManager {
    constructor(private readonly token: string) {
        super();
    }

    async getCopilotToken(ctx: Context): Promise<string> {
        return this.token;
    }

    resetCopilotToken(ctx: Context, httpError: number): void {
        // noop
    }
}


/** Intended for use as an add-on to `CopilotTokenManager`,
 *  that checks that a valid Copilot token is available.
 */
export interface CheckCopilotToken {
    /** Check that the object has access to a valid Copilot token. */
    checkCopilotToken(ctx: Context): Promise<"OK" | TokenError & { reason: Exclude<TokenErrorReason, "GitHubLoginFailed"> }>
}

/**
 * Given a GitHub token, return a Copilot token, refreshing it as needed.
 * The caller that initialises the object is responsible for checking telemetry consent before
 * using the object.
 */
export class CopilotTokenManagerFromGitHubToken extends CopilotTokenManager implements CheckCopilotToken {
    copilotToken: TokenInfo | undefined;

    constructor(private readonly githubToken: string) {
        super();
        this.copilotToken = undefined;
    }

    async getCopilotToken(ctx: Context): Promise<string> {
        if (!this.copilotToken || this.copilotToken.expires_at < nowSeconds()) {
            const tokenResult = await authFromGitHubToken(ctx, this.githubToken);
            if (tokenResult.kind === "failure") {
                throw Error(`Failed to get copilot token: ${tokenResult.reason.toString()} ${tokenResult.message ?? ""}`);
            }
            this.copilotToken = {...tokenResult};
        }
        return this.copilotToken.token;
    }

    async checkCopilotToken(ctx: Context) {
        if (!this.copilotToken || this.copilotToken.expires_at < nowSeconds()) {
            const tokenResult = await authFromGitHubToken(ctx, this.githubToken);
            if (tokenResult.kind === "failure") {
                return tokenResult;
            }
            this.copilotToken = tokenResult;
        }
        return "OK";
    }

    resetCopilotToken(ctx: Context, httpError: number): void {
        telemetry(ctx, "auth.reset_token_" + httpError);
        authLogger.debug(ctx, `Resetting copilot token on HTTP error ${httpError}`);
        this.copilotToken = undefined;
    }
}
