import * as promptlib from '@github/copilot-promptlib';
import { Worker } from 'worker_threads';

let worker: Worker | null = null;

/**
 * A map of pending computations run on the worker thread, each associated with a handler object
 * containing methods `resolve` and `reject`.
 *
 * When a computation on the worker thread completes successfully, the `resolve` method is invoked
 * with the result. If it fails, the `reject` method is invoked with an error object.
 */
const handlers = new Map();
let nextHandlerId = 0;


/**
 * Initialize the worker.
 */
export function init(use_worker_threads: boolean, logger: { error: (msg: any) => void } = console) {
  if (!use_worker_threads) {
    // To enable debugging of promptlib, we load the promptlib through path
    // loading and overwrite the exported functions to call these.
    const localPromptlib = require('../../prompt/src/lib');
    for (const fn of [ ...workerFuns, ...directFuns ]) {
      module.exports[fn] = localPromptlib[fn];
    }
    return;
  }

  // Proxy functions on the worker thread
  for (const fn of workerFuns) {
    module.exports[fn] = proxy(fn as ProxiedFunction);
  }

  worker = promptlib.createWorker();
  handlers.clear();
  nextHandlerId = 0;

  /**
   * Handle the result of a computation returned from the worker.
   */
  worker.on('message', ({ id, err, res }) => {
    const handler = handlers.get(id);
    if (handler) {
      handlers.delete(id);
      if (err) {
        handler.reject(err);
      } else {
        handler.resolve(res);
      }
    }
  });

  /**
   * Handle an unexpected error by logging it and rejecting all handlers.
   */
  function handleError(err: Error) {
    logger.error(err);
    for (const handler of handlers.values()) {
      handler.reject(err);
    }
    handlers.clear();
  }

  worker.on('error', handleError);

  worker.on('exit', code => {
    if (code !== 0) {
      handleError(new Error(`Worker thread exited with code ${code}.`));
    }
  });
}

/**
 * Shut down the worker.
 */
export function terminate() {
  if (worker) {
    worker.removeAllListeners();
    worker.terminate();
    worker = null;
    handlers.clear();
  }
}


/**
 * A type that can be copied using the [structured clone algorithm](https://developer.mozilla.org/en-US/docs/Web/API/Web_Workers_API/Structured_clone_algorithm).
 *
 * Note: This is an approximation; it doesn't currently seem to be possible to capture this precisely
 * (https://github.com/microsoft/TypeScript/issues/29941).
 */
type CloneableType =
  // primitives
  boolean | number | string | undefined |
  // objects with cloneable properties
  { [key in keyof ProxiedInterface] : CloneableType } |
  // arrays with clonable elements
  CloneableType[];

/** The functions we want to proxy to run on the worker thread. */
const workerFuns = [
  'getFunctionPositions' ,
  'isEmptyBlockStart',
  'isBlockBodyFinished',
  'getNodeStart',
  'getPrompt',
  'parsesWithoutError' ] as const;
type ProxiedFunction = typeof workerFuns[number];

/** The functions we want to call directly on the extension host thread. */
const directFuns = [
  'isSupportedLanguageId',
  'getBlockCloseToken' ] as const;

/** The interface types appearing in argument or return types of proxiable functions. */
type ProxiedInterface = promptlib.NodePosition | promptlib.DocumentInfo | promptlib.DocumentInfoWithOffset | promptlib.PromptInfo | promptlib.PromptOptions;

/**
 * Wrap function `fn` from `@github/copilot-promptlib` into a proxy that sends a message
 * with the function name and arguments to the worker and returns a promise that will be
 * resolved with the result the worker returns or rejected with any exception the worker
 * encounters.
 *
 * The wrapped function must return a promise, and its arguments and return values must be
 * primitive values or objects that can be serialized by the worker-threads library.
 */
function proxy<T extends ProxiedFunction>(fn: T): typeof promptlib[T] {
  return function <R extends CloneableType>(...args: CloneableType[]): Promise<R> {
    const id = nextHandlerId++;
    return new Promise((resolve, reject) => {
      handlers.set(id, { resolve, reject });
      worker?.postMessage({ id, fn, args });
    });
  };
}

/**
 * These declarations are added for the type checker.
 * They will be overwritten through module.exports in `init`.
 */
export const isEmptyBlockStart = promptlib.isEmptyBlockStart;
export const isBlockBodyFinished = promptlib.isBlockBodyFinished;
export const isSupportedLanguageId = promptlib.isSupportedLanguageId;
export const getBlockCloseToken = promptlib.getBlockCloseToken;
export const getFunctionPositions = promptlib.getFunctionPositions;
export const getNodeStart = promptlib.getNodeStart;
export const getPrompt = promptlib.getPrompt;
export const parsesWithoutError = promptlib.parsesWithoutError;
export type DocumentInfo = promptlib.DocumentInfo;
