/** We want to be able to run A / B testing experiments with telemetrized groups
 * This file exposes an API to do that.
 * Edit the exported `ABExperiments` object to register new experiments
 */

import { copilotTrackingId } from "../../lib/src/telemetry";
import { env } from 'vscode';
import { SHA256 } from "crypto-js";
import { inTestMode } from "../../lib/src/testing/testMode";
import { isProduction } from "../../lib/src/config";
import { Context } from "../../lib/src/context";

enum Granularity {
    /** Users are allocated randomly, but that allocation is stable */
    ByUser,
    /** For each session, the allocation is the same */
    BySession,
    /** For each machine, the allocation is the same */
    ByMachine,
    /** Each time the group is queried, it's decided randomly
     * If calls are very close to each other, they may share the same allocation */
    ByCall
}

let totalNumberOfExperiments = 0;

class ABExperiment<T extends {[key: string]: number}> {
    public granularity: Granularity;
    private groups: T;
    private default: keyof T;
    private currentGroup?: keyof T;
    private counter = Math.floor(Date.now() / 1000);
    private uniqueExperimentId: number;
    timeRange: [Date?, Date?];

    /**
     * Defines an A / B testing experiment.
     * @param granularity Should each User / Session / Machine / etc
     *                    always have the same allocation to a group?
     * @param groups Give the groups with their relative sizes as key-value pairs.
     *               For example, {A: 1, B: 2} makes two classes A and B,
     *               the latter of which is twice as common (i.e. 33% A vs 66% B).
     * @param defaultGroup The group to fall back on if the experiment is over,
     *                     for tests, etc.
     * @param timeRange Limit the experiment to a time range ([from, to]),
     *                   outside of which the default group is always used.
     *                   This is e.g. advisable if the experiment needs any
     *                   extra infrastructure to be maintained.
     */
    constructor(granularity: Granularity, groups: T, defaultGroup: keyof T, timeRange?: [Date?, Date?]) {
        this.granularity = granularity;
        this.timeRange = timeRange ? [timeRange[0], timeRange[1]] : [undefined, undefined];

        // groups need to have positive weights and non-empty keys
        let sum = 0;
        this.default = defaultGroup;
        for (const key in groups) {
            if (key === "") {
                throw new Error("Group names cannot be empty");
            }
            if (groups[key] < 0) {
                throw new Error("Classes must have positive numbers");
            }
            sum += groups[key];
        }
        // normalize weights to 1
        this.groups = {} as T;
        for (const key in groups) {
            this.groups[key] = groups[key] / sum as T[Extract<keyof T, string>];
        }

        this.uniqueExperimentId = totalNumberOfExperiments++;
    }

    public getGroup(ctx: Context): keyof T {
        const now = new Date();
        if (inTestMode(ctx) || !isProduction()) {
            return this.default;
        }
        if (this.timeRange[0] !== undefined && now < this.timeRange[0] ||
            this.timeRange[1] !== undefined && now > this.timeRange[1]) {
            return this.default;
        }
        if (this.currentGroup) {
            return this.currentGroup;
        }
        switch (this.granularity) {
            case Granularity.ByUser:
                if (copilotTrackingId) {
                    this.currentGroup = this.getGroupFromString(copilotTrackingId);
                    return this.currentGroup;
                } else {
                    // do not set currentGroup: we may be about to set the tracking Id
                    // to make _sure_ it is set, use await getCopilotToken()
                    return this.default;
                }
            case Granularity.BySession:
                this.currentGroup = this.getGroupFromString(env.sessionId);
                return this.currentGroup;
            case Granularity.ByMachine:
                this.currentGroup = this.getGroupFromString(env.machineId);
                return this.currentGroup;
            case Granularity.ByCall:
                return this.getGroupFromString(String(this.counter++));
        }
    }

    /**
     * returns a pseudo-random 32-bit signed integer
     */
    private hash(seed: string): number {
        return SHA256(seed).words[0];
    }

    private getGroupFromString(seed: string): keyof T {
        let hash = this.hash(seed + this.uniqueExperimentId);
        // the hash gives a 32-bit signed integer
        // in order not to deal with negatives:
        hash = Math.abs(hash);
        const scaling = Math.pow(2, 31);
        for (const key in this.groups) {
            const weight = this.groups[key] * scaling;
            if (hash < weight) {
                return key;
            }
            hash -= weight;
        }
        return this.default;
    }
}

/**
 * Get a description of all group memberships that do not change by call.
 * This is intended to be used for telemetry.
 */
export function getConstantExperimentGroups(ctx: Context) {
    const groups: {[key: string]: string} = {};
    for (const experimentName in ABExperiments) {
        groups[experimentName] = "[VARIABLE]";
        const experiment = (ABExperiments as {[key: string]: ABExperiment<any>})[experimentName];
        if (experiment.granularity !== Granularity.ByCall) {
            groups[experimentName] = experiment.getGroup(ctx) as string;
        }
    }
    return groups;
}

export const ABExperiments = {
    /**
     * Define your experiments here, e.g. as:
     * "use_different_engine": new ABExperiment(Granularity.BySession, {"NormalEngine": 95, "ExperimentalEngine": 5}),
     * Then access it by importing abexperiments and going ABExperiments.use_different_engine.getGroup()
     */
    "treesitter_server_trimming_unbuffered": new ABExperiment(Granularity.ByUser, {"parsing": 50, "server": 50}, "parsing", [undefined, new Date("2021-11-10")]),
    "prompt_includes_open_tabs": new ABExperiment(Granularity.BySession, {
        "control:include_none": 20,
        "treatment:include_conservatively": 20,
        "treatment:include_medium": 20,
        "treatment:include_eagerly": 20,
        "treatment:include_eagerly_but_little": 20,
    }, "control:include_none", [new Date("2021-11-12"), new Date("2021-12-01")]),
} as const;
