import { RpcError } from '../rpc';

import { handleGetCompletions, handleGetCompletionsCycling } from './getCompletions';
import handleGetPrompt from './getPrompt';
import handleGetVersion from './getVersion';
import handleHttpRequest from './httpRequest';
import handleSignInInitiate from './signInInitiate';
import handleCheckStatus from './checkStatus';
import handleRecordTelemetryConsent from './recordTelemetryConsent';
import handleSignInConfirm from './signInConfirm';
import { Context } from '../../../lib/src/context';
import handleSignOut from './signOut';

export type MethodSuccess<T> = [T, null];
export type MethodFailure = [null, RpcError];
export type MethodResult<T> = MethodSuccess<T> | MethodFailure;

export type methodHandler<R> = (ctx: Context, params: unknown) => Promise<MethodResult<R>>;

export class MethodHandlers {
    constructor(readonly handlers: Map<string, methodHandler<unknown>>) {}
}

export function getAllMethods(): MethodHandlers {
    const methods = new Map();
    methods.set('getCompletions', handleGetCompletions);
    methods.set('getCompletionsCycling', handleGetCompletionsCycling);
    methods.set('getPrompt', handleGetPrompt);
    methods.set('httpRequest', handleHttpRequest);
    methods.set('getVersion', handleGetVersion);
    methods.set('checkStatus', handleCheckStatus);
    methods.set('signInInitiate', handleSignInInitiate);
    methods.set('signInConfirm', handleSignInConfirm);
    methods.set('signOut', handleSignOut);
    methods.set('recordTelemetryConsent', handleRecordTelemetryConsent);
    return new MethodHandlers(methods);
}
