import * as path from 'path';
import { Worker } from 'worker_threads';

export * from './parse';
export * from './parseBlock';
export * from './prompt';
export * from './tokenizer';

/**
 * Create a worker that can be used to invoke promptlib functions on a separate thread.
 *
 * The worker accepts messages of the form `{ id, fn, args }`, where `id` can be freely chosen by
 * the client, `fn` is the name of a function exported by the promptlib, and `args` is an array
 * of arguments to pass to the function.
 *
 * The worker will run the function named `fn` on a worker thread. If the function returns normally,
 * the worker sends a message `{ id, res }`, where `id` is the same as in the incoming message and
 * `res` is the result of the function. If the function throws an exception, the worker sends a
 * message `{ id, err }`, where `err` is the thrown exception.
 *
 * Note that arguments and results of functions invoked this way must be serializable as described
 * [in the Node.js documentation](https://nodejs.org/api/worker_threads.html#worker_threads_port_postmessage_value_transferlist).
 */
export function createWorker() {
  return new Worker(path.resolve(__dirname, '..', 'dist', 'worker.js'));
}