import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { AuthStatus, AuthManager } from '../auth/manager';
import { Context } from '../../../lib/src/context';

export type Params = {
    options?: {}
};

const paramsSchema = {
    type: 'object',
    properties: {
        options: {
            type: 'object',
            required: [],
            properties: {
            }
            },
      }
};

export type Result = AuthStatus;

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

/** Inform the agent that the user has agreed to the current telemetry terms.
 *  This fact will be persisted on disk so it does not need to be repeated unless
 *  the terms change. If the terms do change, the agent will report `NoTelemetryConsent`
 *  again.
 *
 *  The result will be an `AuthStatus` object either indicating that the user is now fully authenticated,
 *  or that some other problem remains.
*/
export default async function handleRecordTelemetryConsent(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
    if (validParams(params)) {
        const authRecord = await ctx.get(AuthManager).getAuthRecord();
        if (!authRecord) {
            return [null, {
                code: ErrorCode.InvalidRequest,
                message: 'Trying to record telemetry consent but the user is not signed in'
            }];
        }
        ctx.get(AuthManager).recordTelemetryConsent(authRecord.user);
        const status = await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        return [status, null];
    } else {
          const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
          return [null, {
            code: ErrorCode.InvalidParams,
            message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}
