import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { fetch, Method } from 'fetch-h2';
import { Context } from '../../../lib/src/context';

// TODO: add cancellation support

export type Params = {
  url: string,
  method?: string,
  headers?: {[name: string]: string},
  body?: string,
  json?: any,
  timeout?: number
};

export type HttpResponse = {
  status: number,
  statusText: string,
  body: string,
  headers: {}
};

const paramsSchema = {
  type: 'object',
  required: ['url'],
  properties: {
    method: { type: 'string' },
    headers: {
      type: 'object',
      additionalProperties: { type: 'string' }
    },
    body: { type: 'string' },
    json: {},
    timeout: { type: 'number' }
  }
};

// Manually specifying the options we support, since it looks like fetch-h2
// doesn't export all of its types (`FetchInit` is the type we'd want)
type FetchOptions = {
  headers?: { [name: string]: string },
  body?: string,
  timeout?: number,
  json?: any,
  method?: Method
};

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

export default async function handleHttpRequest(ctx: Context, params: unknown): Promise<MethodResult<HttpResponse>> {
  if (validParams(params)) {
    const fetchOptions: FetchOptions = {}

    if ('method' in params) {
      fetchOptions.method = params.method as Method;
    };

    if ('body' in params) {
      fetchOptions.body = params.body;
    }

    if ('json' in params) {
      fetchOptions.json = params.json;
    }

    const timeout = params.timeout;
    if (timeout !== null && timeout !== undefined) {
      fetchOptions.timeout = timeout;
    }
    if (params.headers) {
      fetchOptions.headers = params.headers;
    }
    const fetchResponse = await fetch(params.url, fetchOptions);
    const body = await fetchResponse.text();
    const response = {
      status: fetchResponse.status,
      statusText: fetchResponse.statusText,
      headers: fetchResponse.headers.toJSON(),
      body
    };
    return [response, null];
  } else {
    const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
    return [null, {
      code: ErrorCode.InvalidParams,
      message: 'Invalid params: ' + errorMessages.join(';')
    }];
  }
}
