import { ClientHttp2Stream } from "http2";
import { ICancellationToken } from "../cancellation";
import { Context } from "../context";
import { Logger, LogLevel } from "../logger";
import { Response } from '../networking';
import { FinishedCallback } from "./fetch";
import {
    APIChoice,
    APIJsonData,
    convertToAPIChoice,
    getRequestId,
    RequestId,
} from './openai';

const streamChoicesLogger = new Logger(LogLevel.INFO, "streamChoices");

interface APIJsonDataStreaming {
    logprobs: number[][];
    top_logprobs: {[key: string]: number}[][];
    text: string[];
    tokens: string[][];
    text_offset: number[][];
}

// Given a string of lines separated by one or more newlines, returns complete
// lines and any remaining partial line data. Exported for test only.
export function splitChunk(chunk: string): [string[], string] {
    const dataLines = chunk.split("\n");
    const newExtra = dataLines.pop(); // will be empty string if chunk ends with "\n"
    return [dataLines.filter(line => line != ""), newExtra!];
}

/** A single finished completion returned from the model or proxy, along with some metadata.
 */
interface FinishedCompletion {
    solution: APIJsonDataStreaming;
    /** An optional offset into `solution.text.join('')` where the completion finishes. */
    finishOffset: number | undefined;
    /** A copilot-specific human-readable reason for the completion finishing. */
    reason: string;
    requestId: RequestId;
    index: number;
}

/** Given an HTTP response that we assume is an SSE stream, process
 * it and return any finished completions as they are available.
 */
export async function* processSSE(
        ctx: Context,
        response: Response,
        finishedCb: FinishedCallback,
        cancellationToken?: ICancellationToken): AsyncIterable<FinishedCompletion>
{
    const body: NodeJS.ReadableStream = await response.readable();
    body.setEncoding('utf8');

    // Log headerRequestId once
    let requestId = getRequestId(response);
    streamChoicesLogger.debug(ctx, `requestId: ${requestId.headerRequestId}`);

    // null value for index means we've already finished the solution,
    // and should not process incoming tokens further
    const solutions: Record<number, APIJsonDataStreaming | null> = {};
    let extraData = "";

    for await (const chunk of body) {
        if (cancellationToken?.isCancellationRequested) {
            streamChoicesLogger.info(ctx, "Cancelled after awaiting body chunk");
            (body as ClientHttp2Stream).destroy();
            return;
        }

        streamChoicesLogger.debug(ctx, "chunk", chunk.toString());
        const [dataLines, remainder] = splitChunk(extraData + chunk.toString());
        extraData = remainder;

        for (const dataLine of dataLines) {
            const lineWithoutData = dataLine.slice("data:".length).trim();
            if (lineWithoutData == "[DONE]") {
                for (const [index, solution] of Object.entries(solutions)) {
                    const solutionIndex = Number(index);  // Convert `index` from string to number
                    if (solution == null) {
                        continue;  // already finished
                    }
                    yield { solution, finishOffset: undefined, reason: "DONE", requestId, index: solutionIndex };
                    // NOTE: If we were not returning, we'd want to mark it done:
                    // solutions[solutionIndex] = null;

                    if (cancellationToken?.isCancellationRequested) {
                        streamChoicesLogger.debug(ctx, "Cancelled after yielding on DONE");
                        (body as ClientHttp2Stream).destroy();
                        return;
                    }
                }
                return;
            }

            let json;
            try {
                json = JSON.parse(lineWithoutData);
            } catch (e) {
                streamChoicesLogger.error(ctx, "Error parsing JSON stream data", dataLine);
                continue;
            }

            if (json.choices === undefined && json.error !== undefined) {
                streamChoicesLogger.error(ctx, "Error in response:", json.error.message);
                continue;
            }

            if (requestId.created == 0) {
                // Would only be 0 if we're the first actual response chunk
                requestId = getRequestId(response, json);
                if (requestId.created == 0) {
                    streamChoicesLogger.error(ctx, `Request id invalid, should have "completionId" and "created": ${requestId}`, requestId);
                }
            }

            for (let i = 0; i < json.choices.length; i++) {
                const choice: any = json.choices[i];
                streamChoicesLogger.debug(ctx, "choice", choice);

                if (!(choice.index in solutions)) {
                    solutions[choice.index] = {
                        logprobs: [],
                        top_logprobs: [],
                        text: [],
                        text_offset: [],
                        tokens: [],
                    };
                }

                const solution = solutions[choice.index];
                if (solution == null) {
                    continue;  // already finished
                }

                solution.text.push(choice.text);
                solution.tokens.push(choice.logprobs?.tokens ?? []);
                solution.text_offset.push(choice.logprobs?.text_offset ?? []);
                solution.logprobs.push(choice.logprobs?.token_logprobs ?? []);
                solution.top_logprobs.push(choice.logprobs?.top_logprobs ?? []);

                // Call finishedCb after each newline token to determine
                // if the solution is now complete. Also call it if the
                // solution has finished to make sure it's properly truncated.
                let finishOffset;
                if (choice.finish_reason || choice.text.indexOf("\n") > -1) {
                    finishOffset = await finishedCb(solution.text.join(''));

                    if (cancellationToken?.isCancellationRequested) {
                        streamChoicesLogger.debug(ctx, "Cancelled after awaiting finishedCb");
                        (body as ClientHttp2Stream).destroy();
                        return;
                    }
                }

                // NOTE: When there is a finish_reason the text of subsequent chunks is always '',
                // (current chunk might still have useful text, that is why we add it above).
                // So we know that we already got all the text to be displayed for the user.
                // TODO: This might contain additional logprobs for excluded next tokens. We should
                // filter out indices that correspond to excluded tokens. It will not affect the
                // text though.
                if (choice.finish_reason || finishOffset !== undefined) {
                    yield { solution, finishOffset, reason: JSON.stringify(choice.finish_reason), requestId, index: choice.index};

                    if (cancellationToken?.isCancellationRequested) {
                        streamChoicesLogger.debug(ctx, "Cancelled after yielding finished choice");
                        (body as ClientHttp2Stream).destroy();
                        return;
                    }

                    solutions[choice.index] = null;
                }
            }
        }
    }

    for (const [index, solution] of Object.entries(solutions)) {
        const solutionIndex = Number(index);  // Convert `index` from string to number
        if (solution == null) {
            continue;  // already finished
        }
        yield { solution, finishOffset: undefined, reason: "Iteration Done", requestId, index: solutionIndex };
        // NOTE: If we were not returning, we'd want to mark it done:
        // solutions[solutionIndex] = null;

        if (cancellationToken?.isCancellationRequested) {
            streamChoicesLogger.debug(ctx, "Cancelled after yielding after iteration done");
            (body as ClientHttp2Stream).destroy();
            return;
        }
    }

    // Error message can be present in `extraData`
    if (extraData.length > 0) {
        try {
            const extraDataJson = JSON.parse(extraData);
            if (extraDataJson.error !== undefined) {
                streamChoicesLogger.error(ctx, `Error in response: ${extraDataJson.error.message}`, extraDataJson.error);
            }
        } catch (e) {
            streamChoicesLogger.error(ctx, `Error parsing extraData: ${extraData}`);
        }
    }
}

export function prepareSolutionForReturn(ctx: Context, c: FinishedCompletion): APIChoice {
    let completionText = c.solution.text.join('');

    let blockFinished = false;
    if (c.finishOffset !== undefined) {
        // Trim solution to finishOffset returned by finishedCb
        streamChoicesLogger.debug(ctx,
            `solution ${c.index}: early finish at offset ${c.finishOffset}`);
        completionText = completionText.substring(0, c.finishOffset);
        blockFinished = true;
    }

    streamChoicesLogger.info(ctx, `solution ${c.index} returned. finish reason: [${c.reason}] finishOffset: [${c.finishOffset}] completionId: [{${c.requestId.completionId}}] created: [{${c.requestId.created}}]`);
    const jsonData: APIJsonData = convertToAPIJsonData(ctx, c.solution);
    return convertToAPIChoice(ctx, completionText, jsonData, c.index, c.requestId, blockFinished);
}

// Function to convert from APIJsonDataStreaming to APIJsonData format
function convertToAPIJsonData(ctx: Context, streamingData: APIJsonDataStreaming): APIJsonData {
    const numText = streamingData.text.length;
    const numTokens = streamingData.tokens.length;
    const numOffsets = streamingData.text_offset.length;
    const numLogprobs = streamingData.logprobs.length;
    if (numText !== numTokens || numText !== numOffsets || numTokens !== numLogprobs) {
        streamChoicesLogger.error(ctx, `Invalid streamingData: numText:${numText}, numTokens:${numTokens}, numOffsets:${numOffsets}, numLogprobs:${numLogprobs}`);
    }

    const joinedText = streamingData.text.join("");
    const joinedTokens = streamingData.tokens.map(tokens => tokens.join("")).join("");

    // check that joinedText is a substring of joinedTokens
    // NOTE: In the case of completions "midtoken" then the returned tokens will be a superset of the returned text.
    if (joinedTokens.indexOf(joinedText) < 0) {
        streamChoicesLogger.secureError(ctx, "Invalid streamingData", `joinedText:[${joinedText}] not a substring of joinedTokens:[${joinedTokens}]`);
    }

    const flattenedLogprobs = streamingData.logprobs.reduce((acc, cur) => acc.concat(cur), []);
    const flattenedTopLogprobs = streamingData.top_logprobs.reduce((acc, cur) => acc.concat(cur), []);
    const flattenedOffsets = streamingData.text_offset.reduce((acc, cur) => acc.concat(cur), []);
    const flattenedTokens = streamingData.tokens.reduce((acc, cur) => acc.concat(cur), []);

    return {
        text: joinedText,
        logprobs :{
            token_logprobs: flattenedLogprobs,
            top_logprobs: flattenedTopLogprobs,
            text_offset: flattenedOffsets,
            tokens: flattenedTokens,
        }
    };
}
