import { defaultFileSystem, FileSystem } from './fileSystem';
import { getLanguageMarker, getPathMarker } from './languageMarker';
import { extractLocalImportContext } from "./localImportContext";
import { getSiblingFunctions } from "./siblingFunctions";
import { Priorities, PromptChoices, PromptElementKind, PromptWishlist } from "./wishlist";
import { getNeighborSnippets } from './neighboringFiles';

/** The maximum number of tokens in a prompt. */
export const MAX_PROMPT_LENGTH = 1500;


/**
 * Information about a document, not including the offset.
 */
export interface DocumentInfo {
    /** The absolute file path of the document, if known. */
    path?: string;
    /** The file path of the document relative to its containing project or folder, if known. */
    relativePath?: string;
    /** The source text of the document. */
    source: string;
    /** The language identifier of the document. */
    languageId: string;
}

/**
 * Information about a document, including an offset corresponding to
 * the cursor position.
 */
export interface DocumentInfoWithOffset extends DocumentInfo {
    /** The offset in the document where we want the completion (0-indexed, between characters). */
    offset: number;
}

export enum LanguageMarkerOption {
    NoMarker = "nomarker",
    Top = "top",           // Emulate that the first line of document is the language marker
    Always = "always",     // Always visible
}

export enum PathMarkerOption {
    NoMarker = "nomarker",
    Top = "top",
    Always = "always",
}

export enum SiblingOption {
    NoSiblings = "nosiblings",
    SiblingsOverContext = "siblingabove", // Including siblings is more important than context before cursor
    ContextOverSiblings = "contextabove"  // Context before cursor is more important than including siblings
}

export enum NeighboringTabsOption {
    None = "none",
    Conservative = "conservative",
    Medium = "medium",
    Eager = "eager",
    EagerButLittle = "eagerButLittle"
}

export enum LocalImportContextOption {
    /** Don't pull in any context for local imports. */
    NoContext = "nocontext",
    /** Pull in declarations referenced by local imports. */
    Declarations = "declarations"
}

export enum LineEndingOptions {
    ConvertToUnix = "unix", // convert "\r\n" and "\r" line endings to the more token-efficient \n
    KeepOriginal = "keep",  // keep the original line endings (whether \r\n or \n)
}

export interface PromptOptions {
    // Optional arguments given to the prompt crafter.
    // If not set, defaults are set at the top of `getPrompt`.
    maxPromptLength?: number;
    languageMarker?: LanguageMarkerOption;
    pathMarker?: PathMarkerOption;
    includeSiblingFunctions?: SiblingOption;
    localImportContext?: LocalImportContextOption;
    neighboringTabs?: NeighboringTabsOption;
    lineEnding?: LineEndingOptions;
    fs?: FileSystem;
}

export interface PromptInfo {
    prompt: string;                 // The prompt text
    promptLength: number;           // The length of the prompt in tokens
    promptChoices: PromptChoices;   // Which choices were made when constructing the prompt
}

/**
 * A map that normalises common aliases of languageIds.
 */
const languageNormalizationMap: { [language: string]: string } = {
    "javascriptreact": "javascript",
    "jsx":             "javascript",
    "typescriptreact": "typescript",
    "jade":            "pug",
    "cshtml":          "razor",
};

/**
 * Return a normalized form of a language id, by lower casing and combining
 * certain languageId's that are not considered distinct by promptlib.
 */
export function normalizeLanguageId(languageId: string) : string {
    languageId = languageId.toLowerCase();
    return languageNormalizationMap[languageId] ?? languageId;
}

export function newLineEnded(str: string) {
    return (str == "" || str.endsWith('\n')) ? str : str + '\n';
}

/**
 * Constructs a prompt to pass to the OpenAI API.
 *
 * @remarks
 * The current implementation does the simplest thing possible: It estimates the number of
 * characters that will fit within the maximum length of a prompt in tokens, then returns a
 * substring of doc that starts at some reasonable index and ends at offset, such that
 * (end - start) <= estimated_length.
 *
 * This will change in the future.
 *
 * @param doc - A DocumentInfoWithOffset
 * @param options - A PromptOptions which controls the prompt crafting behaviour.
 * @param neighbors - A list of neighboring documents, e.g., documents open in other
 *                    editor tabs.
 *
 * @returns A dictionary containing the prompt to pass to the OpenAI API and the
 * resulting prompt length in tokens.
 */
export async function getPrompt(
    doc: DocumentInfoWithOffset,
    {   maxPromptLength = MAX_PROMPT_LENGTH,
        languageMarker = LanguageMarkerOption.Top,
        pathMarker = PathMarkerOption.Top,
        includeSiblingFunctions = SiblingOption.ContextOverSiblings,
        localImportContext = LocalImportContextOption.Declarations,
        neighboringTabs = NeighboringTabsOption.None,
        lineEnding = LineEndingOptions.ConvertToUnix,
        fs = defaultFileSystem
    }: PromptOptions = {},
    neighbors: DocumentInfo[] = [],
): Promise<PromptInfo> {
    const { source, offset } = doc;
    if (offset < 0 || offset > source.length) {
        throw new Error(`Offset ${offset} is out of range.`);
    }
    doc.languageId = normalizeLanguageId(doc.languageId);

    // Make explicit the priorities implied by the different options
    const priorities = new Priorities();
    const directContextPriority =
        priorities.justBelow(Priorities.TOP);
    const pathMarkerPriority = pathMarker == PathMarkerOption.Always ?
        priorities.justBelow(Priorities.TOP) :
        priorities.justBelow(directContextPriority);
    const languageMarkerPriority = languageMarker == LanguageMarkerOption.Always ?
        priorities.justBelow(Priorities.TOP) :
        priorities.justBelow(directContextPriority);
    const siblingPriority = includeSiblingFunctions == SiblingOption.ContextOverSiblings ?
        priorities.justBelow(directContextPriority) :
        priorities.justAbove(directContextPriority);
    const localImportContextPriority =
        priorities.justBelow(directContextPriority, siblingPriority);
    const relevantNeighborPriority = 
        priorities.justBelow(localImportContextPriority);

    // The wishlist keeps track of what we would like to include in the prompt
    const promptWishlist = new PromptWishlist(lineEnding);

    let languageMarkerLine: number | undefined;
    if (languageMarker != LanguageMarkerOption.NoMarker) {
        const languageMarker = newLineEnded(getLanguageMarker(doc));
        languageMarkerLine = promptWishlist.append(languageMarker,
            PromptElementKind.LanguageMarker,
            languageMarkerPriority);
        }

    let pathMarkerLine: number | undefined;
    if (pathMarker != PathMarkerOption.NoMarker) {
        const pathMarker = newLineEnded(getPathMarker(doc));
        pathMarkerLine = promptWishlist.append(pathMarker,
            PromptElementKind.PathMarker,
            pathMarkerPriority);
        }

    // imports get inserted after the language / path markers, but before anything from the file itself
    if (localImportContext != LocalImportContextOption.NoContext) {
        for (const localImportContext of await extractLocalImportContext(doc, fs)) {
            promptWishlist.append(
                newLineEnded(localImportContext),
                PromptElementKind.ImportedFile,
                localImportContextPriority);
        }
    }

    if (neighboringTabs != NeighboringTabsOption.None && neighbors.length > 0) {
        const neighborSnippets =  
            await getNeighborSnippets(doc, neighbors, neighboringTabs);
        // appending them in order means better scores being added later
        // (i.e. will take precedence if not all fit)
        neighborSnippets.forEach(snippet => 
            promptWishlist.append(
                snippet,
                PromptElementKind.SimilarFile,
                relevantNeighborPriority)
        );
    }

    let source_lines : number[] = [];
    if (includeSiblingFunctions == SiblingOption.NoSiblings) {
        source_lines = promptWishlist.appendLineForLine(source.substring(0, offset),
            PromptElementKind.BeforeCursor,
            directContextPriority);
    } else {
        const { siblings, beforeInsertion, afterInsertion } = await getSiblingFunctions(doc);
        promptWishlist.appendLineForLine(beforeInsertion, PromptElementKind.BeforeCursor, directContextPriority);
        // we want to add earlier siblings with higher priority, so we keep track of the next sibling's priority
        let nextSiblingsPriority = siblingPriority;
        siblings.forEach(sibling => {
            promptWishlist.append(sibling, PromptElementKind.AfterCursor, nextSiblingsPriority);
            nextSiblingsPriority = priorities.justBelow(nextSiblingsPriority);
        });
        source_lines = promptWishlist.appendLineForLine(afterInsertion, PromptElementKind.BeforeCursor, directContextPriority);
    }

    // the marker options `Top` intend to simulate the file beginning with the markers
    // so the markers should depend on the first line of source code --
    // if that is missing, so should they be
    if (LanguageMarkerOption.Top == languageMarker
        && source_lines.length > 0
        && languageMarkerLine !== undefined) {
            promptWishlist.require(languageMarkerLine, source_lines[0]);
    }
    if (PathMarkerOption.Top == pathMarker
        && source_lines.length > 0
        && pathMarkerLine !== undefined) {
        languageMarkerLine?
                promptWishlist.require(pathMarkerLine, languageMarkerLine)
                : promptWishlist.require(pathMarkerLine, source_lines[0]);
    }
    return promptWishlist.fulfill(maxPromptLength);
}