// The original from https://github.com/latitudegames/GPT-3-Encoder 
// includes code which was modified from https://github.com/openai/gpt-2
//
// Important invariants about tokenization:
// - Tokenization works by a first pass that splits the text into chunks using
//   the regular expression `pat`.
// - Each chunk is then split into tokens.
// - All chunks' tokens are then concatenated to form the complete tokenization.
// - Newlines appear in only three tokens: "\n", "\n\n", "\n"+nonbreaking space 

const VOCAB = "vocab.bpe";
const ENCODER = "tokenizer.json";

const fs = require('fs')
const path = require('path');

/////
// Helper functions
/////

const range = (x, y) => {
  const res = Array.from(Array(y).keys()).slice(x)
  return res
}

const ord = x => {
  return x.charCodeAt(0)
}

const chr = x => {
  return String.fromCharCode(x)
}

const textDecoder = new TextDecoder("utf-8")
const decodeStr = arr => {
  return textDecoder.decode(new Uint8Array(arr));
}

const dictZip = (x, y) => {
  const result = {}
  x.map((_, i) => { result[x[i]] = y[i] })
  return result
}

function bytes_to_unicode(map) {
  const bs = range(ord('!'), ord('~') + 1).concat(range(ord('¡'), ord('¬') + 1), range(ord('®'), ord('ÿ') + 1))

  let cs = bs.slice()
  let n = 0
  for (let b = 0; b < 2 ** 8; b++) {
    if (!bs.includes(b)) {
      bs.push(b)
      cs.push(2 ** 8 + n)
      n = n + 1
    }
  }

  cs = cs.map(x => chr(x))
  for (let i = 0; i < bs.length; i++) {
    map.set(bs[i], cs[i])
  }
}

function get_pairs(word) {
  const pairs = new Set()
  let prev_char = word[0]
  for (let i = 1; i < word.length; i++) {
    const char = word[i]
    pairs.add([prev_char, char])
    prev_char = char
  }
  return pairs
}


const textEncoder = new TextEncoder("utf-8")
const encodeStr = str => {
  return Array.from(textEncoder.encode(str))
}
function byteEncodeStr(s) {
  return encodeStr(s).map(x => byte_encoder.get(x))
}

const pat = /'s|'t|'re|'ve|'m|'ll|'d| ?\p{L}+| ?\p{N}+| ?[^\s\p{L}\p{N}]+|\s+(?!\S)|\s+/gu

// Global variables holding the tokenization information
// Populated by prepare
let prepared = false;
const decoder = {};
let encoder = {};
let bpe_ranks;
let byte_encoder = new Map();
let byte_decoder = new Map();
const cache = new Map();

function prepareTokenizer() {
  if (prepared) { return; }
  encoder = JSON.parse(fs.readFileSync(path.resolve(__dirname, '..', 'dist', ENCODER)));
  Object.keys(encoder).map(x => { decoder[encoder[x]] = x })

  const bpe_file = fs.readFileSync(path.resolve(__dirname, '..', 'dist', VOCAB), 'utf-8');
  const lines = bpe_file.split('\n')
  const bpe_merges = lines.slice(1, lines.length - 1).map(x => {
    return x.split(/(\s+)/).filter(function(e) { return e.trim().length > 0 })
  })
  bpe_ranks = dictZip(bpe_merges, range(0, bpe_merges.length))

  bytes_to_unicode(byte_encoder)
  byte_encoder.forEach(function (value, key, _) {
    byte_decoder.set(value, key)
  })
  prepared = true;
}

function bpe(chunk) {
  if (cache.has(chunk)) {
    return cache.get(chunk);
  }
  let bytes = byteEncodeStr(chunk)
  let pairs = get_pairs(bytes)
  if (!pairs) {
    return bytes.map(x => encoder[x])
  }

  while (true) {
    const minPairs = {}
    Array.from(pairs).map(pair => {
      const rank = bpe_ranks[pair]
      minPairs[(isNaN(rank) ? 10e10 : rank)] = pair
    })



    const bigram = minPairs[Math.min(...Object.keys(minPairs).map(x => {
      return parseInt(x)
    }
    ))]

    if (!(bigram in bpe_ranks)) {
      break
    }

    const first = bigram[0]
    const second = bigram[1]
    let new_bytes = []
    let i = 0

    while (i < bytes.length) {
      const j = bytes.indexOf(first, i)
      if (j === -1) {
        Array.prototype.push.apply(new_bytes, bytes.slice(i))
        break
      }
      Array.prototype.push.apply(new_bytes, bytes.slice(i, j))
      i = j

      if (bytes[i] === first && i < bytes.length - 1 && bytes[i + 1] === second) {
        new_bytes.push(first + second)
        i = i + 2
      } else {
        new_bytes.push(bytes[i])
        i = i + 1
      }
    }

    bytes = new_bytes
    if (bytes.length === 1) {
      break
    } else {
      pairs = get_pairs(bytes)
    }
  }

  tokens = bytes.map(x => encoder[x])
  cache.set(chunk, tokens)

  return tokens 
}

/**
 * Returns the tokenization of the input string as a list of integers
 * representing tokens.
 */
function tokenize(text) {
  prepareTokenizer();
  let tokens = []
  const matches = Array.from(text.matchAll(pat)).map(x => x[0])
  for (let chunk of matches) {
    const chunk_tokens = bpe(chunk)
    Array.prototype.push.apply(tokens, chunk_tokens)
  }
  return tokens
}

/**
 * Return the length of `text` in number of tokens.
 * 
 * @param {str} text - The input text
 * @returns {number}
 */
function tokenLength(text) {
  return tokenize(text).length;
}

/**
 * Return a suffix of `text` which is `n` tokens long.
 * If `text` is at most `n` tokens, return `text`.
 * 
 * Note: This implementation is not proven to return the longest possible
 * suffix. In rare cases, due to tokenization not being stable under
 * prepends, it may return a suffix which is a 1-2 characters too short.
 * 
 * @param {string} text - The text from which to take
 * @param {number} n - How many tokens to take
 * @returns A suffix of `text`, as a `string`.
 */
function takeLastTokens(text, n) {
  if (n <= 0) return "";

  // Find long enough suffix of text that has >= n tokens
  const CHARS_PER_TOKENS_START = 4;
  const CHARS_PER_TOKENS_ADD = 1;
  let chars = Math.min(text.length, n*CHARS_PER_TOKENS_START) //First guess
  let suffix = text.slice(-chars);
  let suffix_t = tokenize(suffix);
  while (suffix_t.length < n && chars < text.length) {
    chars = Math.min(text.length, chars + n*CHARS_PER_TOKENS_ADD);
    suffix = text.slice(-chars);
    suffix_t = tokenize(suffix);
  }
  if (suffix_t.length < n) {
    // text must be <= n tokens long
    return text;
  }
  // Cut off last n tokens
  suffix_t = suffix_t.slice(-n);
  suffix = detokenize(suffix_t);

  // Add a few more chars to the first token while still retaining 1 token
  let first_token = detokenize(suffix_t.slice(0,1));
  const mid = text.length - suffix.length;
  let i=0;
  while (mid-i > 0 && tokenLength(text.substring(mid-i-1,mid) + first_token) === 1) {
    i++;
  }
  return text.substring(mid-i, mid) + suffix;
}

/**
 * Return the longest suffix of `text` of complete lines and is at most
 * `n` tokens long.
 * @param {string} text - The text from which to take
 * @param {number} n - How many tokens to take
 */
function takeLastLinesTokens(text, n) {
  const suffix = takeLastTokens(text, n);
  if (suffix.length === text.length || text[text.length-suffix.length-1] === '\n') {
    // Edge case: We already took whole lines
    return suffix;
  }
  let newline = suffix.indexOf('\n');
  return suffix.substring(newline+1);
}

/**
 * Returns the string representation of the tokens in `tokens`, given in integer
 * representation.
 * 
 * This is the functional inverse of `tokenize`.
 */
function detokenize(tokens) {
  prepareTokenizer();

  let text = tokens.map(x => decoder[x]).join('')
  text = decodeStr(text.split('').map(x => byte_decoder.get(x)))
  return text
}

/**
 * Returns the tokenization of the input string as a list of strings.
 * 
 * The concatenation of the output of this function is equal to the input.
 */
function tokenize_strings(text) {
  const tokens = tokenize(text);
  return tokens.map(token =>
    decodeStr(
      decoder[token]
      .split('')
      .map(char => byte_decoder.get(char)))
    );
}

module.exports = {
  prepareTokenizer,
  tokenize,
  tokenize_strings,
  tokenLength,
  takeLastTokens,
  takeLastLinesTokens,
  detokenize
}
