import { Position, Range, TextDocument } from 'vscode';

import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodSuccess, MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { getGhostText } from '../../../lib/src/ghostText/ghostText';
import { TextDocument as CompatTextDocument } from '../compat/vscode';
import { extractPromptForSource, PromptBuilderCustomization } from '../../../lib/src/prompt';
import { completionsFromGhostTextResults } from '../../../lib/src/ghostText/copilotCompletion';
import { CopilotTokenManager, FixedCopilotTokenManager } from '../../../lib/src/auth/copilotToken';
import { Context } from '../../../lib/src/context';
import { AuthManager } from '../auth/manager';
import { BlockMode, ConfigKey, getConfig } from '../../../lib/src/config';
import { CancellationTokenSource } from '../cancellation';

export type Params = {
  doc: {
    source: string,
    languageId: string,
    position: Position,
    insertSpaces?: boolean,
    tabSize?: number
    path: string,
    relativePath: string
  },
  /** This field is transitional and will be removed in future.
   *  The caller can use it to pass in a Copilot token rather than relying
   *  on the agent to obtain one.
   */
  token?: string,
  options?: {}
};

export type Result = {
  completions: Array<{
    text: string,
    range: Range,
    displayText: string,
    position: Position
  }>
};

const paramsSchema = {
  type: 'object',
  required: ['doc'],
  properties: {
    doc: {
      type: 'object',
      required: ['path', 'relativePath', 'source', 'position', 'languageId'],
      properties: {
        path: { type: 'string'},
        relativePath: { type: 'string' },
        source: { type: 'string' },
        position: {
          type: 'object',
          required: ['line', 'character'],
          properties: {
            line: { type: 'number' },
            character: { type: 'number' }
          }
        },
        languageId: { type: 'string' },
        tabSize: { type: 'number' },
        insertSpaces: { type: 'boolean' }
        // omitting `fs` since it isn't representable in json
      }
    },
    options: {
      type: 'object',
      required: [],
      properties: {
      }
    },
    token: { type: 'string' }
  }
};

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

let cancellationTokenSource: CancellationTokenSource | undefined;

async function handleGetCompletionsHelper(ctx: Context, params: unknown, tokenManager: CopilotTokenManager | undefined = undefined, isCycling: boolean): Promise<MethodResult<Result>> {
  //This implements `cancel-previous` behavior. Whenever we get new `getCompletions` or `getCompletionsCycling` requests, we cancel the previous one.
  if(cancellationTokenSource) {
    cancellationTokenSource.cancel();
    cancellationTokenSource.dispose();
  }
  cancellationTokenSource = new CancellationTokenSource();

  if (validParams(params)) {

    if (params.token !== undefined) {
        // Transitional support: the client passed in a token so we'll use it.
        tokenManager = new FixedCopilotTokenManager(params.token);
    }

    if (tokenManager === undefined) {
        // Hopefully there's already a token manager setup.
        tokenManager = ctx.get(AuthManager).getCopilotTokenManager();
    }

    if (tokenManager === undefined) {
        // If not, let's find out why.
        const authResult = await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        if (authResult.status !== 'OK') {
            return [null, {
                code: ErrorCode.NoCopilotToken,
                message: `Not authenticated: ${authResult.status}`
            }];
        }
        tokenManager = ctx.get(AuthManager).getCopilotTokenManager();
        if (tokenManager === undefined) {
            // This case should be impossible because if `checkAndUpdateStatus` returned `OK` then
            // it should have set up a token manager.
            return [null, {
                code: ErrorCode.InternalError,
                message: `Unexpected missing Copilot token`
            }];
        }
    }

    // TODO(drifkin): `vscode-languageserver-textdocument`'s `TextDocument` uses a plain string for
    // the URI, whereas vscode uses an object. We're setting the string here, but any code that
    // relies on vscode's Uri class won't work. We should move away from impersonating the `vscode`
    // module soon anyway.  Note that the current telemetry code does rely on this Uri class, so
    // once we add agent telemetry we need to reconcile this
    const uri = `file://${params.doc.path}`;
    const textDocument = CompatTextDocument.create(
      uri, params.doc.languageId, 1, params.doc.source) as unknown as TextDocument;

    const source = params.doc.source;
    const offset = textDocument.offsetAt(new Position(params.doc.position.line, params.doc.position.character));
    const languageId = textDocument.languageId;
    const path = params.doc.path;
    const relativePath = params.doc.relativePath;
    const position = textDocument.positionAt(offset);

    const promptCustomizations : PromptBuilderCustomization = {
      getOpenFiles: undefined,
      getSolutionLength: () => getConfig<number>(ConfigKey.SolutionLength),
      getExperimentGroup: (ctx) => ""
  }

    const promptResponse = await extractPromptForSource(ctx, source, offset, path, relativePath, languageId, promptCustomizations);
    if (promptResponse.type === 'contextTooShort') {
        // ghostTextLogger.debug("Breaking, not enough context");
        return returnNoCompletions();
    }
    const blockMode = BlockMode.Server;

    const requestCtx = new Context(ctx);
    requestCtx.set(CopilotTokenManager, tokenManager);
    const result = await getGhostText(requestCtx, textDocument, position, promptResponse, blockMode, isCycling, cancellationTokenSource.token);
    if (!result) {
      return returnNoCompletions();
    }
    const [resultArray, resultType] = result;

    // TODO(drifkin): once we have agent telemetry, add in the post-rejection
    // telemetry currently found in `provideInlineCompletions`

    const rawCompletions = completionsFromGhostTextResults(resultArray, resultType, textDocument, position, params.doc);
    const completions = rawCompletions.map(rawCompletion => {
      return {
        text: rawCompletion.text,
        range: rawCompletion.range,
        displayText: rawCompletion.displayText,
        position: rawCompletion.position
      };
    });

    return [{ completions }, null];
  } else {
    const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
    return [null, {
      code: ErrorCode.InvalidParams,
      message: 'Invalid params: ' + errorMessages.join(';')
    }];
  }
}

function returnNoCompletions(): MethodSuccess<Result> {
  return [{ completions: [] }, null];
}

export async function handleGetCompletions(ctx: Context, params: unknown, tokenManager: CopilotTokenManager | undefined = undefined) {
  return handleGetCompletionsHelper(ctx, params, tokenManager, false);
}

export async function handleGetCompletionsCycling(ctx: Context, params: unknown, tokenManager: CopilotTokenManager | undefined = undefined) {
  return handleGetCompletionsHelper(ctx, params, tokenManager, true);
}